import React, { useContext, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { LogOut, Calendar, Home, Menu, X } from 'lucide-react';
import './Navbar.css';

const Navbar = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  /**
   * Helper to safely extract and format the role name.
   * Handles: "ROLE_USER", ["ROLE_USER"], or [{authority: "ROLE_USER"}]
   */
  const getDisplayRole = () => {
    if (!user || !user.role) return '';

    // 1. Get the raw role value (handle array if needed)
    const rawRole = Array.isArray(user.role) ? user.role[0] : user.role;

    // 2. Extract the string (handle object structure if needed)
    const roleString = typeof rawRole === 'object' ? rawRole.authority : rawRole;

    // 3. Clean up the string for display
    return typeof roleString === 'string' 
      ? roleString.replace('ROLE_', '').toLowerCase() 
      : '';
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
    setIsMobileMenuOpen(false);
  };

  const displayRole = getDisplayRole();

  return (
    <nav className="navbar">
      <div className="navbar-container">
        {/* Logo */}
        <Link to="/" className="logo">
          <div className="logo-icon">
            <Home size={22} />
          </div>
          <span>MockInterviews</span>
        </Link>

        {/* Desktop Navigation */}
        <div className="desktop-nav">
          {!user ? (
            <div className="auth-buttons">
              <Link to="/login" className="login-link">Login</Link>
              <Link to="/register" className="btn-primary">Get Started</Link>
            </div>
          ) : (
            <>
              <div className="nav-links">
                {displayRole === 'interviewer' && (
                  <Link to="/interviewer/availability" className="nav-item">
                    <Calendar size={20} />
                    <span>Availability</span>
                  </Link>
                )}

                {displayRole === 'candidate' && (
                  <Link to="/candidate/search" className="nav-item">
                    Find Interviewers
                  </Link>
                )}
              </div>

              {/* User Profile */}
              <div className="user-menu">
                <div className="user-profile">
                  <div className="avatar">
                    {user.sub?.charAt(0).toUpperCase() || 'U'}
                  </div>
                  <div className="user-info">
                    <p className="user-name">{user.sub}</p>
                    <p className="user-role">{displayRole}</p>
                  </div>
                </div>

                <button onClick={handleLogout} className="logout-btn" title="Logout">
                  <LogOut size={20} />
                </button>
              </div>
            </>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button
          className="mobile-menu-btn"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Menu Content */}
      {isMobileMenuOpen && (
        <div className="mobile-menu">
          <div className="mobile-menu-content">
            {!user ? (
              <>
                <Link to="/login" className="mobile-link" onClick={() => setIsMobileMenuOpen(false)}>Login</Link>
                <Link to="/register" className="btn-primary mobile-cta" onClick={() => setIsMobileMenuOpen(false)}>Get Started</Link>
              </>
            ) : (
              <>
                {displayRole === 'interviewer' && (
                  <Link to="/interviewer/availability" className="mobile-link" onClick={() => setIsMobileMenuOpen(false)}>
                    <Calendar size={24} /> Availability
                  </Link>
                )}

                {displayRole === 'candidate' && (
                  <Link to="/candidate/search" className="mobile-link" onClick={() => setIsMobileMenuOpen(false)}>
                    Find Interviewers
                  </Link>
                )}

                <div className="mobile-user-section">
                  <div className="mobile-user-profile">
                    <div className="avatar avatar-large">
                      {user.sub?.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <p className="user-name">{user.sub}</p>
                      <p className="user-role">{displayRole}</p>
                    </div>
                  </div>
                  <button onClick={handleLogout} className="logout-btn">
                    <LogOut size={24} />
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
